using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using verii_metivon_api.Modules.Pricing.Domain.Entities;namespace verii_metivon_api.Modules.Pricing.Infrastructure.Persistence.Configurations;
public sealed class PriceListConfiguration:IEntityTypeConfiguration<PriceList>{public void Configure(EntityTypeBuilder<PriceList>b){b.ToTable("RII_PRICE_LISTS");b.HasIndex(x=>x.Code).IsUnique();b.HasOne(x=>x.Currency).WithMany().HasForeignKey(x=>x.CurrencyId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class PriceListLineConfiguration:IEntityTypeConfiguration<PriceListLine>{public void Configure(EntityTypeBuilder<PriceListLine>b){b.ToTable("RII_PRICE_LIST_LINES");b.HasIndex(x=>new{x.PriceListId,x.ProductId,x.UnitId,x.CustomerGroupId,x.MinimumQuantity,x.ValidFrom}).IsUnique();b.Property(x=>x.MinimumQuantity).HasPrecision(24,8);b.Property(x=>x.UnitPrice).HasPrecision(24,8);b.HasOne(x=>x.PriceList).WithMany(x=>x.Lines).HasForeignKey(x=>x.PriceListId).OnDelete(DeleteBehavior.Restrict);}}
public sealed class DiscountRuleConfiguration:IEntityTypeConfiguration<DiscountRule>{public void Configure(EntityTypeBuilder<DiscountRule>b){b.ToTable("RII_DISCOUNT_RULES");b.HasIndex(x=>x.Code).IsUnique();b.Property(x=>x.MinimumQuantity).HasPrecision(24,8);b.Property(x=>x.DiscountRate).HasPrecision(9,6);b.Property(x=>x.DiscountAmount).HasPrecision(24,8);b.Property(x=>x.MaximumDiscountAmount).HasPrecision(24,8);}}
public sealed class PricingParameterSettingsConfiguration:IEntityTypeConfiguration<PricingParameterSettings>{public void Configure(EntityTypeBuilder<PricingParameterSettings>b){b.ToTable("RII_PRICING_PARAMETERS",t=>{t.HasCheckConstraint("CK_RII_PRICING_PARAMETERS_PRICE_ROUNDING","[PriceRoundingDecimals] >= 0 AND [PriceRoundingDecimals] <= 8");t.HasCheckConstraint("CK_RII_PRICING_PARAMETERS_DISCOUNT_ROUNDING","[DiscountRoundingDecimals] >= 0 AND [DiscountRoundingDecimals] <= 8");t.HasCheckConstraint("CK_RII_PRICING_PARAMETERS_ROUNDING_METHOD","[RoundingMethod] >= 0 AND [RoundingMethod] <= 3");t.HasCheckConstraint("CK_RII_PRICING_PARAMETERS_MAX_RULES","[MaximumDiscountRulesApplied] >= 1 AND [MaximumDiscountRulesApplied] <= 100");t.HasCheckConstraint("CK_RII_PRICING_PARAMETERS_MAX_DISCOUNT","[MaximumTotalDiscountPercent] >= 0 AND [MaximumTotalDiscountPercent] <= 100");});b.HasKey(x=>x.Id);b.HasQueryFilter(x=>!x.IsDeleted);b.HasIndex(x=>x.BranchId).IsUnique().HasFilter("[IsDeleted] = 0");b.Property(x=>x.MaximumTotalDiscountPercent).HasPrecision(9,6);b.Property(x=>x.RowVersion).IsRowVersion();b.HasOne(x=>x.Branch).WithMany().HasForeignKey(x=>x.BranchId).OnDelete(DeleteBehavior.Restrict);}}
